-- Apply through the deployment migration process before disabling Sequelize sync in production.
CREATE TABLE IF NOT EXISTS brands (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, uuid CHAR(36) NOT NULL UNIQUE, name VARCHAR(150) NOT NULL UNIQUE, active TINYINT(1) NOT NULL DEFAULT 1, created_by BIGINT UNSIGNED NULL, updated_by BIGINT UNSIGNED NULL, created_at DATETIME NOT NULL, updated_at DATETIME NOT NULL, deleted_at DATETIME NULL);
ALTER TABLE materials ADD COLUMN brand_id BIGINT UNSIGNED NULL, ADD COLUMN category_id BIGINT UNSIGNED NULL, ADD COLUMN property_id BIGINT UNSIGNED NULL, ADD COLUMN model VARCHAR(150) NULL, ADD COLUMN serial_number VARCHAR(150) NULL UNIQUE, ADD COLUMN year INT UNSIGNED NULL, ADD COLUMN purchase_date DATE NULL, ADD COLUMN current_value DECIMAL(12,2) NULL, ADD COLUMN engine_hours DECIMAL(10,2) NULL, ADD COLUMN commissioned_at DATE NULL, ADD COLUMN retired_at DATE NULL, ADD COLUMN notes TEXT NULL;
ALTER TABLE materials ADD INDEX idx_materials_brand_id (brand_id), ADD INDEX idx_materials_category_id (category_id), ADD INDEX idx_materials_property_id (property_id), ADD CONSTRAINT fk_materials_brand FOREIGN KEY (brand_id) REFERENCES brands(id) ON DELETE SET NULL, ADD CONSTRAINT fk_materials_category FOREIGN KEY (category_id) REFERENCES categories(id) ON DELETE SET NULL, ADD CONSTRAINT fk_materials_property FOREIGN KEY (property_id) REFERENCES properties(id) ON DELETE SET NULL;
CREATE TABLE IF NOT EXISTS material_files (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, uuid CHAR(36) NOT NULL UNIQUE, material_id BIGINT UNSIGNED NOT NULL, kind ENUM('photo','document') NOT NULL, document_type ENUM('invoice','manual','certificate','other') NULL, original_name VARCHAR(255) NOT NULL, file_name VARCHAR(255) NOT NULL, mime_type VARCHAR(100) NOT NULL, size INT UNSIGNED NOT NULL, is_primary TINYINT(1) NOT NULL DEFAULT 0, created_at DATETIME NOT NULL, INDEX idx_material_files_material_id (material_id), CONSTRAINT fk_material_files_material FOREIGN KEY (material_id) REFERENCES materials(id) ON DELETE CASCADE);
